const exec = $json;
const runData = (exec.data && exec.data.resultData && exec.data.resultData.runData) || {};
let runId = null;
let nicheId = null;
const triggerRuns = runData['Execute Workflow Trigger'];
if (triggerRuns && triggerRuns[0] && triggerRuns[0].data && triggerRuns[0].data.main && triggerRuns[0].data.main[0] && triggerRuns[0].data.main[0][0]) {
  const input = triggerRuns[0].data.main[0][0].json || {};
  runId = input.run_id != null ? input.run_id : null;
  nicheId = input.niche_id != null ? input.niche_id : null;
}
const errTrigger = $node["Error Trigger"].json;
return [{
  json: {
    runId,
    nicheId,
    workflowName: (errTrigger.workflow && errTrigger.workflow.name) || 'desconhecido',
    lastNodeExecuted: (errTrigger.execution && errTrigger.execution.lastNodeExecuted) || 'desconhecido',
    errorMessage: (errTrigger.execution && errTrigger.execution.error && errTrigger.execution.error.message) || 'erro desconhecido',
    executionUrl: (errTrigger.execution && errTrigger.execution.url) || ''
  }
}];

